#include <bits/stdc++.h>
using namespace std;
int d[4][2]={{1,0},{0,1},{-1,0},{0,-1}};
int n,m,a[102][102],ans=0;
string s;
bool to[102][102];
void bfs(int sx,int sy){
    queue<int> qx,qy;
    qx.push(sx),qy.push(sy),to[sx][sy]=1;
    while(qx.size()){
        int fx=qx.front(),fy=qy.front();
        qx.pop(),qy.pop();
        for(int i=0;i<4;i++){
            int xx=fx+d[i][0],yy=fy+d[i][1];
            if(xx>0 && yy>0 && xx<=n && yy<=m && a[xx][yy] && !to[xx][yy])
                to[xx][yy]=1,qx.push(xx),qy.push(yy);
        }
    }
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
    	cin>>s;
        for(int j=1;j<=m;j++)
            a[i][j]=s[j-1]-'0';
    }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            if(a[i][j] && !to[i][j])
                bfs(i,j),ans++;
    printf("%d",ans);
    return 0;
}
